// ── FIXED: Handle both Tuleap webhook formats ──────────────────────────────
// Format A (legacy): application/x-www-form-urlencoded, body = { payload: '<JSON string>' }
// Format B (current): application/json, body = { artifact, project, user }

const raw = $input.first().json;
// In n8n v1+ with typeVersion 2, form fields are hoisted; check both locations
const body = (raw.body !== undefined && typeof raw.body === 'object') ? raw.body : raw;

let payload;

if (body.payload !== undefined) {
  // Format A: payload key contains a JSON string (or already-parsed object)
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
  // Validate the parsed payload has the expected shape
  if (!payload || typeof payload !== 'object') {
    throw new Error('Parsed payload is not a valid object');
  }
} else if (body.artifact !== undefined) {
  // Format B: direct JSON — normalize to the same internal shape
  payload = {
    current: body.artifact,
    project: body.project || null,
    user: body.user || null,
    action: body.action || 'artifact:created'
  };
} else {
  const keys = Object.keys(body).join(', ') || '(empty body)';
  throw new Error(`Unrecognized Tuleap webhook format. Body keys: ${keys}. Check Tuleap webhook configuration.`);
}

// Validate the artifact and tracker exist
const tracker = payload.tracker || payload.current?.tracker;
if (!tracker?.id) {
  throw new Error(
    `Missing tracker.id in payload. ` +
    `tracker = ${JSON.stringify(tracker)}`
  );
}

return [{ json: { payload } }];

// Find the sync config matching this tracker ID
const payload = $('Parse Payload').first().json.payload;
const configs = $('Fetch Sync Config').first().json.data || [];
const trackerId = payload?.tracker?.id;

const config = configs.find(c => String(c.tuleap_tracker_id) === String(trackerId));
if (!config) {
  return [{ json: { hasConfig: false, trackerId, payload } }];
}
return [{ json: { hasConfig: true, config, payload } }];

// Build a synthetic config from the auto-provisioned QC project
const parsed  = $('Match Config').first().json;
const apiResp = $input.first().json;

const qcProject = apiResp.data;
if (!qcProject?.id) {
  throw new Error(`Project provisioning failed. API response: ${JSON.stringify(apiResp).slice(0, 300)}`);
}

const config = {
  qc_project_id:     qcProject.id,
  qc_project_name:   qcProject.project_name || null,
  tuleap_project_id: parsed.payload?.project?.id || null,
  tuleap_base_url:   null,
  status_mappings:   {}
};

return [{ json: { hasConfig: true, config, payload: parsed.payload } }];

const { config, payload } = $input.first().json;
const artifact = payload.current;
const statusMappings = config.status_mappings || {};

const fields = {};
for (const v of (artifact.values || [])) { fields[v.label] = v; }

function txt(...labels) {
  for (const lbl of labels) {
    const f = fields[lbl];
    if (!f) continue;
    if (f.value !== undefined && f.value !== null) return String(f.value);
  }
  return null;
}

function sel(...labels) {
  for (const lbl of labels) {
    const f = fields[lbl];
    if (!f) continue;
    if (f.values && f.values[0]) return f.values[0].label || f.values[0].display_name || String(f.values[0]);
  }
  return null;
}

function user(...labels) {
  for (const lbl of labels) {
    const f = fields[lbl];
    if (!f || !f.values) continue;
    const u = f.values[0];
    if (u) return u.display_name || u.real_name || u.username || null;
  }
  return null;
}

function mapStatus(s) {
  if (!s) return 'Open';
  return statusMappings[s] || { New:'Open', Open:'open', Assigned:'In Progress',
    Fixed:'Resolved', Resolved:'Resolved', Closed:'Closed',
    Rejected:'Closed', Reopened:'Reopened' }[s] || 'Open';
}

function mapSeverity(s) {
  if (!s) return 'medium';
  const lower = s.toLowerCase();
  if (lower.includes('critical')) return 'critical';
  if (lower.includes('major'))     return 'high';
  if (lower.includes('minor'))     return 'medium';
  if (lower.includes('cosmetic'))  return 'low';
  if (lower.includes('high'))      return 'high';
  if (lower.includes('medium'))    return 'medium';
  if (lower.includes('normal'))    return 'medium';
  if (lower.includes('low'))       return 'low';
  return 'medium';
}

const artifactId = payload.id || artifact.id;
const allValues = artifact.values || [];

// Check if bug has links to Test Case trackers via art_link fields
const hasTestCaseLink = allValues.some(v =>
  v.type === 'art_link' &&
  (
    (Array.isArray(v.links) &&
      v.links.some(link => link.tracker && link.tracker.label === 'Test Case')) ||
    (Array.isArray(v.reverse_links) &&
      v.reverse_links.some(link => link.tracker && link.tracker.label === 'Test Case'))
  )
);

const source = hasTestCaseLink ? 'TEST_CASE' : 'EXPLORATORY';

const bugData = {
  tuleap_artifact_id: artifactId,
  tuleap_tracker_id:  payload.tracker?.id,
  tuleap_url: config.tuleap_base_url ? `${config.tuleap_base_url}/plugins/tracker/?aid=${artifactId}` : null,
  bug_id:       `TLP-${artifactId}`,
  title:        txt('Bug Title','Summary','Title','summary','title') || `Bug ${artifactId}`,
  description:  txt('Description + Steps to reproduce','Description','Details','Original Submission','description'),
  status:       mapStatus(sel('Status','status')),
  severity:     mapSeverity(sel('Severity','severity','Importance')),
  priority:     (sel('Priority','priority') || 'medium').toLowerCase(),
  bug_type:     sel('Type','Category','Bug Type','type'),
  component:    sel('Component','Module','component'),
  project_id:   config.qc_project_id,
  linked_test_case_ids: [],
  linked_test_execution_ids: [],
  reported_by:  payload.user?.display_name || null,
  updated_by:   payload.user?.display_name || null,
  assigned_to:  user('Assigned to','Assigned To','assigned_to'),
  reported_date: artifact.submitted_on || null,
  raw_tuleap_payload: payload,
  source: source,
  submitted_by_email: artifact.submitted_by?.email ?? null,
  submitted_by_username: artifact.submitted_by?.username ?? null
};

return [{ json: { bugData } }];
